import { useEffect } from "react";
import { Routes, Route, useLocation, Navigate } from "react-router-dom";

import Login from "./pages/Login";
import HackerDashboard from "./pages/HackerDashboard";
import CompanyDashboard from "./pages/CompanyDashboard";
import CompanyPendingBugs from "./pages/CompanyPendingBugs";
import CompanyBugHistory from "./pages/CompanyBugHistory";
import SubmitBug from "./pages/SubmitBug";
import MyBugs from "./pages/MyBugs";
import Wallet from "./pages/Wallet";
import Register from "./pages/Register";
import CompanyAnalytics from "./pages/CompanyAnalytics";
import CompanyWallet from "./pages/CompanyWallet";

export default function App() {
  const location = useLocation();

  const token = localStorage.getItem("token");
  const role = localStorage.getItem("role");

  useEffect(() => {
    document.body.classList.remove("hacker-theme");
    document.body.classList.remove("company-theme");

    if (role === "company" || role === "admin") {
      document.body.classList.add("company-theme");
    } else if (role === "hacker") {
      document.body.classList.add("hacker-theme");
    }
  }, [location, role]);

  return (
    <Routes>
      {/* ALWAYS REDIRECT ROOT TO LOGIN */}
      <Route path="/" element={<Navigate to="/login" />} />

      {/* LOGIN PAGE */}
      <Route path="/login" element={<Login />} />

      {/* Hacker Routes */}
      <Route
        path="/hacker"
        element={token && role === "hacker" ? <HackerDashboard /> : <Navigate to="/login" />}
      />
      <Route
        path="/submit-bug"
        element={token && role === "hacker" ? <SubmitBug /> : <Navigate to="/login" />}
      />
      <Route
        path="/my-bugs"
        element={token && role === "hacker" ? <MyBugs /> : <Navigate to="/login" />}
      />
      <Route
        path="/wallet"
        element={token && role === "hacker" ? <Wallet /> : <Navigate to="/login" />}
      />

      {/* Company Routes */}
      <Route
        path="/company"
        element={token && role === "company" ? <CompanyDashboard /> : <Navigate to="/login" />}
      />
      <Route
        path="/company/pending"
        element={token && role === "company" ? <CompanyPendingBugs /> : <Navigate to="/login" />}
      />
      <Route
        path="/company/history"
        element={token && role === "company" ? <CompanyBugHistory /> : <Navigate to="/login" />}
      />
      <Route
        path="/company/analytics"
        element={token && role === "company" ? <CompanyAnalytics /> : <Navigate to="/login" />}
      />
      <Route
        path="/company/wallet"
        element={token && role === "company" ? <CompanyWallet /> : <Navigate to="/login" />}
      />

      <Route path="/register" element={<Register />} />

      {/* Catch All */}
      <Route path="*" element={<Navigate to="/login" />} />
    </Routes>
  );
}
